import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.7R1OEGYz.js";const p=JSON.parse('{"title":"Create an account","description":"","frontmatter":{},"headers":[],"relativePath":"using/create-account.md","filePath":"using/create-account.md"}'),s={name:"using/create-account.md"};function r(i,e,c,h,l,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="create-an-account" tabindex="-1">Create an account <a class="header-anchor" href="#create-an-account" aria-label="Permalink to &quot;Create an account&quot;">​</a></h1><p>A fresh browser can become a verified, named account in a few taps. You need no wallet, no extension, and no ETH to start.</p><h2 id="the-flow" tabindex="-1">The flow <a class="header-anchor" href="#the-flow" aria-label="Permalink to &quot;The flow&quot;">​</a></h2><ol><li>Open the app. A fresh profile shows <strong>Create your Suho account</strong>.</li><li>Tap it and complete the passkey prompt. This is your key. No seed phrase is ever made.</li><li>Your account exists. The screen shows your address, &quot;Not yet verified&quot;, and a zero balance.</li><li>A guided checklist appears on the home screen.</li></ol><p>The checklist has four steps. Each is a real on-chain milestone that flips to a seal when done.</p><ul><li><strong>Fund.</strong> Send a little testnet ETH from a faucet. The balance updates live.</li><li><strong>Get verified.</strong> Your account attests itself with the testnet issuer. This costs a small fee and is passkey-signed.</li><li><strong>Claim your name.</strong> Pick a up.id. The account claims it, so the name is owned by you.</li><li><strong>Send your first transfer.</strong> Try a verified name and watch the seal resolve.</li></ul><h2 id="what-happens-under-the-hood" tabindex="-1">What happens under the hood <a class="header-anchor" href="#what-happens-under-the-hood" aria-label="Permalink to &quot;What happens under the hood&quot;">​</a></h2><p>When you tap create, the browser generates a one-time key, uses it to sign two things, and destroys it. The two signatures authorize the account and bind your passkey to it. The guardian submits one transaction and pays the gas.</p><p>The account is born at its own address, already a smart account. From then on your passkey is the authority. See <a href="/docs/internals/custody">Custody and threat model</a> for why the one-time key is safe.</p><p>Onboarding was proven live. <a href="https://sepolia-explorer.giwa.io/tx/0xf00bd017430c9e0d6d25afc389767410f0a923820f0b701cdd7f7ce0b50bce42" target="_blank" rel="noreferrer">View the activation transaction.</a></p><h2 id="the-demo-account" tabindex="-1">The demo account <a class="header-anchor" href="#the-demo-account" aria-label="Permalink to &quot;The demo account&quot;">​</a></h2><p>The app ships with a demo account (alice.up.id) on a clearly labeled legacy path. Use it to explore without onboarding. New accounts always use the current flow above.</p>',12)])])}const f=a(s,[["render",r]]);export{p as __pageData,f as default};
